env = {
    "ANTHROPIC_API_KEY": "sk-ant-test",
    "DEBUG": "True",
}

def load_config(env):
    api_key = env.get("ANTHROPIC_API_KEY")
    if not api_key:
        raise RuntimeError("ANTHROPIC_API_KEY missing")
    model = env.get("MODEL", "claude-sonnet-4-6")
    debug = env.get("DEBUG", "false").lower() == "true"
    return {"api_key": api_key, "model": model, "debug": debug}

cfg = load_config(env)
print(f"api_key={cfg['api_key']}")
print(f"model={cfg['model']}")
print(f"debug={cfg['debug']}")

files = [
    {"path": "src/auth.py", "content": "api_key = os.getenv('ANTHROPIC_API_KEY')"},
    {"path": ".env", "content": "ANTHROPIC_API_KEY=sk-ant-real"},
    {"path": ".env.example", "content": "ANTHROPIC_API_KEY="},
    {"path": "src/bad.py", "content": 'api_key = "sk-ant-leaked-key"'},
]

def audit_files(files):
    warnings = []
    for f in files:
        path = f["path"]
        content = f["content"]
        is_env_file = path == ".env" or (path.startswith(".env.") and path != ".env.example")
        if is_env_file:
            warnings.append(f"do not commit {path}")
            continue
        if "sk-ant-" in content or "sk-test-" in content:
            warnings.append(f"hardcoded key in {path}")
    return warnings

for warning in audit_files(files):
    print(warning)
